import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useContext, useState } from 'react';
import { Image, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import { AuthContext } from '../../App';
import AppIcon from '../components/AppIcon';
import CustomerBottomNav from '../components/CustomerBottomNav';
import OrderStatusTracker from '../components/OrderStatusTracker';
import {
  formatCurrency,
  formatOrderNumber,
  ORDER_STATUS_META,
  WATER_PRODUCT
} from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { fetchCustomerOrders, fetchInventorySummary, OrderRecord } from '../services/firebaseService';
import waterCanImage from '../assets/20-l-water-can1.jpg';

type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'CustomerHome'>;

const CustomerHomeScreen = () => {
  const { profile } = useContext(AuthContext);
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [liveStock, setLiveStock] = useState(WATER_PRODUCT.availableStock);

  useFocusEffect(
    useCallback(() => {
      let active = true;
      const load = async () => {
        if (!profile?.uid) { setOrders([]); return; }
        const [data, inv] = await Promise.all([
          fetchCustomerOrders(profile.uid).catch(() => []),
          fetchInventorySummary().catch(() => null)
        ]);
        if (!active) return;
        setOrders(data);
        if (inv) {
          setLiveStock(Math.max(0, (inv.openingStock ?? 0) + (inv.restockedCans ?? 0) - (inv.soldCans ?? 0)));
        }
      };
      load();
      return () => { active = false; };
    }, [profile?.uid])
  );

  const activeOrder = orders.find((o) =>
    ['pending', 'confirmed', 'preparing', 'out_for_delivery'].includes(o.status)
  ) ?? null;
  const lastOrder = orders[0] ?? null;

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>

        {/* Top bar */}
        <View style={styles.topBar}>
          <View>
            <Text style={styles.greeting}>Hello, {profile?.name?.split(' ')[0] || 'Customer'} 👋</Text>
            <Text style={styles.shopName}>Thanni CAN</Text>
          </View>
          <Pressable style={styles.profileBtn} onPress={() => navigation.navigate('Profile')}>
            <AppIcon name="person" size={20} color="#1E7A45" />
          </Pressable>
        </View>

        {/* Hero image */}
        <View style={styles.heroCard}>
          <Image source={waterCanImage} style={styles.heroImage} resizeMode="cover" />
          <View style={styles.heroOverlay}>
            <View style={styles.heroBadge}>
              <Text style={styles.heroBadgeText}>Fresh • Pure • Fast</Text>
            </View>
            <Text style={styles.heroTitle}>20L Drinking{'\n'}Water Can</Text>
          </View>
        </View>

        {/* Product details card */}
        <View style={styles.productCard}>
          <View style={styles.productRow}>
            <View style={styles.productInfo}>
              <Text style={styles.productName}>{WATER_PRODUCT.name}</Text>
              <Text style={styles.productSubtitle}>{WATER_PRODUCT.subtitle}</Text>
            </View>
            <View style={styles.priceBox}>
              <Text style={styles.priceValue}>{formatCurrency(WATER_PRODUCT.pricePerCan)}</Text>
              <Text style={styles.priceLabel}>per can</Text>
            </View>
          </View>

          <View style={styles.statsRow}>
            <View style={styles.statBox}>
              <AppIcon name="cube-outline" size={16} color="#1E7A45" />
              <Text style={styles.statValue}>{liveStock}</Text>
              <Text style={styles.statLabel}>In stock</Text>
            </View>
            <View style={styles.statDivider} />
            <View style={styles.statBox}>
              <AppIcon name="time-outline" size={16} color="#1E7A45" />
              <Text style={styles.statValue}>30 min</Text>
              <Text style={styles.statLabel}>Express</Text>
            </View>
            <View style={styles.statDivider} />
            <View style={styles.statBox}>
              <AppIcon name="receipt-outline" size={16} color="#1E7A45" />
              <Text style={styles.statValue}>{orders.length}</Text>
              <Text style={styles.statLabel}>My orders</Text>
            </View>
          </View>

          {liveStock <= WATER_PRODUCT.lowStockThreshold ? (
            <View style={styles.lowStockBanner}>
              <AppIcon name="warning-outline" size={14} color="#B45309" />
              <Text style={styles.lowStockText}>Only {liveStock} cans left — order soon!</Text>
            </View>
          ) : null}
        </View>

        {/* Order button */}
        <Pressable style={styles.orderBtn} onPress={() => navigation.navigate('NewOrder', {})}>
          <AppIcon name="add-circle-outline" size={22} color="#fff" />
          <Text style={styles.orderBtnText}>Order Now</Text>
        </Pressable>

        <Pressable style={styles.secondaryBtn} onPress={() => navigation.navigate('CustomerOrders')}>
          <AppIcon name="receipt-outline" size={18} color="#1E7A45" />
          <Text style={styles.secondaryBtnText}>My Orders</Text>
        </Pressable>

        {/* Active order */}
        {activeOrder ? (
          <View style={styles.card}>
            <View style={styles.cardTitleRow}>
              <View>
                <Text style={styles.cardTitle}>Active order</Text>
                <Text style={styles.cardSub}>
                  {formatOrderNumber(activeOrder)} • {formatCurrency(activeOrder.totalAmount)}
                </Text>
              </View>
              <Pressable
                style={styles.trackBtn}
                onPress={() => navigation.navigate('OrderTracking', { orderId: activeOrder.id })}
              >
                <Text style={styles.trackBtnText}>Track</Text>
              </Pressable>
            </View>
            <OrderStatusTracker status={activeOrder.status} compact />
            <View style={styles.tileRow}>
              <View style={styles.tile}>
                <Text style={styles.tileLabel}>Quantity</Text>
                <Text style={styles.tileValue}>{activeOrder.quantity} cans</Text>
              </View>
              <View style={styles.tile}>
                <Text style={styles.tileLabel}>ETA</Text>
                <Text style={styles.tileValue}>{activeOrder.expectedDeliveryTime}</Text>
              </View>
            </View>
          </View>
        ) : null}

        {/* Last order summary */}
        {lastOrder ? (
          <View style={styles.card}>
            <View style={styles.cardTitleRow}>
              <Text style={styles.cardTitle}>Last order</Text>
              <Pressable
                style={styles.trackBtn}
                onPress={() => navigation.navigate('OrderDetails', { orderId: lastOrder.id! })}
              >
                <Text style={styles.trackBtnText}>Details</Text>
              </Pressable>
            </View>
            <View style={styles.lastOrderRow}>
              <View style={[styles.statusDot, { backgroundColor: ORDER_STATUS_META[lastOrder.status].accent }]} />
              <Text style={styles.lastOrderNum}>{formatOrderNumber(lastOrder)}</Text>
              <Text style={styles.lastOrderStatus}>{ORDER_STATUS_META[lastOrder.status].label}</Text>
            </View>
            <View style={styles.tileRow}>
              <View style={styles.tile}>
                <Text style={styles.tileLabel}>Amount</Text>
                <Text style={styles.tileValue}>{formatCurrency(lastOrder.totalAmount)}</Text>
              </View>
              <View style={styles.tile}>
                <Text style={styles.tileLabel}>Payment</Text>
                <Text style={styles.tileValue}>{lastOrder.paymentMethod}</Text>
              </View>
            </View>
            <Pressable
              style={styles.reorderBtn}
              onPress={() => navigation.navigate('NewOrder', { reorder: true })}
            >
              <AppIcon name="refresh-outline" size={16} color="#1E7A45" />
              <Text style={styles.reorderBtnText}>Reorder</Text>
            </Pressable>
          </View>
        ) : null}

      </ScrollView>
      <CustomerBottomNav active="CustomerHome" />
    </SafeAreaView>
  );
};

